-- Sync stabilization P2: sensitivity-gated read policy for project_sync_events.
--
-- Companion to 20260713110000 (the domain-event triggers). Split into its own
-- ALLOWLISTED migration so the curated backend-truth mirror reflects this
-- tightened read contract: 20260713110000 is curated-excluded (statement
-- triggers + SECURITY DEFINER functions + cron), and a policy DROP/CREATE
-- buried there would leave the mirror publishing the wider P1 policy
-- (can_access_project only) while production enforces the narrower one.
--
-- The P1 ledger SELECT policy gated on can_access_project only — fine when only
-- 'projection'/'estimate_draft' (no sensitive metadata) flowed. Now that
-- hr/hr_payments/procurement/members events carry actor + timestamp for
-- access-gated domains, a member who cannot SELECT those rows must not learn
-- who touched them and when via the feed either. Recreate the policy so each
-- gated kind is visible ONLY to members who pass the SAME visibility the
-- underlying table requires:
--   * procurement            → can_view_sensitive_detail
--   * hr / hr_payments        → can_view_sensitive_detail AND can_access_hr_domain
--   * members                 → can_manage_project (owner/co_owner see the full
--     member list; a member who can see only their OWN project_members row must
--     not learn who changed the roster and when — they catch up on their own
--     role change via focus refetch, same as pre-realtime).
-- All other kinds keep the plain can_access_project gate. Realtime (WALRUS) uses
-- this same SELECT policy, so live delivery is gated identically. Members who
-- fail a gate lose nothing they could otherwise read.

drop policy if exists project_sync_events_select on public.project_sync_events;

create policy project_sync_events_select on public.project_sync_events
  for select to authenticated
  using (
    public.can_access_project(project_id)
    and (
      kind not in ('procurement', 'hr', 'hr_payments', 'members')
      or (kind = 'procurement' and public.can_view_sensitive_detail(project_id))
      or (kind in ('hr', 'hr_payments')
          and public.can_view_sensitive_detail(project_id)
          and public.can_access_hr_domain(project_id))
      or (kind = 'members' and public.can_manage_project(project_id))
    )
  );
